#include <stdio.h>
int main() {
    int T, a, b, n;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d", &a, &b, &n);
        int x[n];
        x[0] = 1;
        for (int k = 1; k < n; k++) {
            int candidate = x[k-1] + 1;
            while (1) {
                int valid = 1;
                for (int i = 0; i < k; i++) {
                    for (int j = 0; j < k; j++) {
                        if (candidate == a*x[i] - b*x[j]) {
                            valid = 0;
                            break;
                        }
                    }
                    if (!valid) break;
                }
                if (valid) {
                    x[k] = candidate;
                    break;
                }
                candidate++;
            }
        }
        for (int i = 0; i < n; i++) {
            printf("%d ", x[i]);
        }
        printf("\n");
    }
    return 0;
}

